// Domain catalog: each domain is a hand-authored roadmap of topics.
// The lesson CONTENT for each topic is generated by AI on demand, so adding a
// domain or topic is just data — no per-topic authoring needed.

export interface DomainTopic {
  slug: string;
  title: string;
  blurb: string;
}

export interface Domain {
  slug: string;
  name: string;
  emoji: string;
  blurb: string;
  gradient: string;
  free: boolean; // whole domain free vs Pro
  roadmap: DomainTopic[];
}

/** Number of topics in each domain that are free for the free tier. */
export const FREE_TOPICS_PER_DOMAIN = 3;

