export function getDomain(slug: string): Domain | undefined {
  return DOMAINS.find((d) => d.slug === slug);
}

export function getDomainTopic(domainSlug: string, topicSlug: string): { domain: Domain; topic: DomainTopic; index: number } | undefined {
  const domain = getDomain(domainSlug);
  if (!domain) return undefined;
  const index = domain.roadmap.findIndex((t) => t.slug === topicSlug);
  if (index < 0) return undefined;
  return { domain, topic: domain.roadmap[index], index };
}

/** A topic is unlocked if it's the first, or the previous topic is mastered. */
export function isTopicUnlocked(index: number, masteredSlugs: Set<string>, roadmap: DomainTopic[]): boolean {
  if (index <= 0) return true;
  return masteredSlugs.has(roadmap[index - 1].slug);
}

/** A topic is accessible by plan if it's among the first free topics, or the user is Pro. */
export function isTopicAccessible(index: number, domain: Domain, pro: boolean): boolean {
  if (pro) return true;
  if (domain.free) return index < FREE_TOPICS_PER_DOMAIN;
  return false;
}
